import React, { useMemo, useRef } from 'react';
import './WordCloud.css';

const palette = ['#2563eb', '#0f766e', '#7c3aed', '#d97706', '#dc2626', '#0891b2', '#2f855a'];

const WordCloud = ({ data, onWordClick, onWordLongPress, selectionMode, selectedItems }) => {
  const longPressTimer = useRef(null);
  const containerRef = useRef(null);

  const wordLayout = useMemo(() => {
    if (!data || Object.keys(data).length === 0) return [];

    const hasCollision = (x, y, fontSize, existingPositions) => {
      const padding = 10;
      for (const pos of existingPositions) {
        const dx = x - pos.x;
        const dy = y - pos.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        const minDistance = (fontSize + pos.fontSize) / 2 + padding;
        if (distance < minDistance) return true;
      }
      return false;
    };

    const entries = Object.entries(data);
    const maxCount = Math.max(...entries.map(([_, count]) => count));
    const minCount = Math.min(...entries.map(([_, count]) => count));

    const words = entries.map(([word, count], index) => {
      const normalizedCount = (count - minCount) / (maxCount - minCount || 1);
      const fontSize = 20 + (normalizedCount * normalizedCount) * 40;
      return {
        text: word,
        count,
        fontSize: Math.round(fontSize),
        color: palette[index % palette.length]
      };
    });

    words.sort((a, b) => b.fontSize - a.fontSize);

    const placed = [];
    const maxWidth = 1200;
    const maxHeight = 600;
    const centerX = maxWidth / 2;
    const centerY = maxHeight / 2 - 50;
    const positions = [];

    words.forEach((word, index) => {
      let x, y;
      let attempts = 0;
      const maxAttempts = 100;

      do {
        if (index === 0) {
          x = centerX;
          y = centerY;
        } else {
          const angle = Math.random() * Math.PI * 2;
          const radiusX = (Math.random() * 0.7 + 0.3) * maxWidth / 2.5;
          const radiusY = (Math.random() * 0.7 + 0.3) * maxHeight / 2.5;
          x = centerX + Math.cos(angle) * radiusX;
          y = centerY + Math.sin(angle) * radiusY;
        }
        attempts++;
      } while (attempts < maxAttempts && hasCollision(x, y, word.fontSize, positions));

      positions.push({
        x,
        y,
        fontSize: word.fontSize,
        width: word.text.length * word.fontSize * 0.6
      });

      placed.push({ ...word, x, y, key: word.text });
    });

    return placed;
  }, [data]);

  const handleMouseDown = (word) => {
    longPressTimer.current = setTimeout(() => {
      onWordLongPress(word);
    }, 500);
  };

  const handleMouseUp = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
    }
  };

  const handleClick = (word, e) => {
    e.stopPropagation();
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
    }
    onWordClick(word);
  };

  const handleTouchStart = (word) => {
    longPressTimer.current = setTimeout(() => {
      onWordLongPress(word);
    }, 500);
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
    }
  };

  return (
    <div ref={containerRef} className={`word-cloud-container ${selectionMode ? 'selection-mode' : ''}`}>
      <svg className="word-cloud-svg" viewBox="0 0 1200 600" preserveAspectRatio="xMidYMid meet">
        {wordLayout.map(word => (
          <text
            key={word.key}
            className={`cloud-word ${selectedItems?.has(word.text) ? 'selected' : ''}`}
            x={word.x}
            y={word.y}
            textAnchor="middle"
            dominantBaseline="middle"
            fontSize={word.fontSize}
            style={{ color: word.color, fill: word.color, pointerEvents: 'all', cursor: 'pointer' }}
            onMouseDown={() => handleMouseDown(word.text)}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onClick={(e) => handleClick(word.text, e)}
            onTouchStart={() => handleTouchStart(word.text)}
            onTouchEnd={handleTouchEnd}
          >
            {word.text} ({word.count})
          </text>
        ))}
      </svg>
    </div>
  );
};

export default WordCloud;
